"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[4111],{4111:e=>{e.exports=JSON.parse('{"38":{"words":[{"spanish":"los derechos civiles","english":"civil rights"},{"spanish":"el tr\xe1mite administrativo","english":"administrative procedure"},{"spanish":"la denuncia formal","english":"formal complaint"},{"spanish":"el ayuntamiento","english":"city hall"},{"spanish":"la junta vecinal","english":"neighborhood council"},{"spanish":"el jurado","english":"jury"},{"spanish":"la ley","english":"the law"},{"spanish":"el reglamento","english":"regulation"},{"spanish":"la ordenanza municipal","english":"municipal ordinance"},{"spanish":"el funcionario p\xfablico","english":"public official"},{"spanish":"la participaci\xf3n ciudadana","english":"citizen participation"},{"spanish":"presentar una queja","english":"to file a complaint"},{"spanish":"solicitar un permiso","english":"to request a permit"},{"spanish":"el expediente","english":"case file"},{"spanish":"el plazo de resoluci\xf3n","english":"decision deadline"},{"spanish":"la ventanilla \xfanica","english":"one-stop service desk"},{"spanish":"el certificado de empadronamiento","english":"residence registration certificate"},{"spanish":"el recurso administrativo","english":"administrative appeal"},{"spanish":"la audiencia p\xfablica","english":"public hearing"},{"spanish":"la mediaci\xf3n","english":"mediation"},{"spanish":"la comparecencia","english":"appearance"},{"spanish":"el acta oficial","english":"official record"},{"spanish":"el acceso a la informaci\xf3n p\xfablica","english":"access to public information"},{"spanish":"la licencia de obras","english":"building permit"},{"spanish":"el permiso de ocupaci\xf3n","english":"occupancy permit"},{"spanish":"las pruebas documentales","english":"documentary evidence"},{"spanish":"la firma electr\xf3nica","english":"electronic signature"},{"spanish":"la cita previa","english":"appointment booking"},{"spanish":"la resoluci\xf3n motivada","english":"reasoned decision"},{"spanish":"el silencio administrativo","english":"administrative silence"},{"spanish":"el servicio de limpieza","english":"sanitation service"},{"spanish":"la v\xeda p\xfablica","english":"public roadway"},{"spanish":"la convivencia vecinal","english":"neighborhood coexistence"},{"spanish":"la infracci\xf3n","english":"violation"},{"spanish":"la sanci\xf3n","english":"penalty"},{"spanish":"el derecho de audiencia","english":"right to be heard"},{"spanish":"la oficina de atenci\xf3n ciudadana","english":"citizen service office"},{"spanish":"el registro oficial","english":"official registry"},{"spanish":"subsanar documentaci\xf3n","english":"to remedy missing documents"},{"spanish":"el reglamento interno","english":"internal regulation"},{"spanish":"el horario de atenci\xf3n","english":"office hours"},{"spanish":"el servicio esencial","english":"essential service"},{"spanish":"el espacio p\xfablico","english":"public space"},{"spanish":"la asociaci\xf3n vecinal","english":"neighborhood association"},{"spanish":"la solicitud por escrito","english":"written request"}],"conversations":[{"id":1,"topic":"Solicitud de permiso para una feria vecinal","dialog":[{"speaker":"Ana","spanish":"Buenos d\xedas. Represento a una asociaci\xf3n vecinal y querr\xedamos solicitar un permiso para organizar una feria de reparaci\xf3n en la plaza del barrio.","english":"Good morning. I represent a neighborhood association, and we would like to request a permit to organize a repair fair in the neighborhood square."},{"speaker":"Se\xf1or Ruiz","spanish":"Con mucho gusto. Para tramitar la solicitud, necesitar\xe1n un plan de seguridad, el horario previsto y un justificante del seguro de responsabilidad civil.","english":"Certainly. To process the request, you will need a safety plan, the proposed schedule, and proof of liability insurance."},{"speaker":"Ana","spanish":"Algunos puestos ser\xedan educativos y no habr\xeda m\xfasica amplificada despu\xe9s de las nueve. \xbfPodr\xedamos presentar todo por v\xeda digital si la documentaci\xf3n estuviera firmada electr\xf3nicamente?","english":"Some booths would be educational, and there would be no amplified music after nine. Could we submit everything digitally if the paperwork were electronically signed?"},{"speaker":"Se\xf1or Ruiz","spanish":"S\xed, pueden registrarlo en l\xednea, pero si faltara alg\xfan documento, se les requerir\xe1 que lo subsanen en un plazo de diez d\xedas h\xe1biles.","english":"Yes, you can file it online, but if any document is missing, you will be asked to correct it within ten business days."},{"speaker":"Ana","spanish":"Entiendo. Como se trata de una actividad sin \xe1nimo de lucro, quisiera saber si existe alguna reducci\xf3n o exenci\xf3n de la tasa municipal.","english":"I understand. Since this is a non-profit activity, I would like to know whether any reduction or exemption from the municipal fee exists."},{"speaker":"Se\xf1or Ruiz","spanish":"Podr\xeda concederse si se acredita el inter\xe9s p\xfablico del evento y si quedan previstas medidas claras de limpieza y convivencia vecinal.","english":"It could be granted if the event\'s public interest is demonstrated and if clear sanitation and neighborhood coexistence measures are included."}],"questions":[{"question":"\xbfQu\xe9 documentaci\xf3n b\xe1sica menciona el funcionario para iniciar el tr\xe1mite?","options":["Un plan de seguridad, el horario y un justificante del seguro.","Solo una carta de invitaci\xf3n y una lista de voluntarios.","El acta de la \xfaltima junta escolar y un presupuesto privado.","\xdanicamente una fotograf\xeda de la plaza donde se celebrar\xe1 la feria."],"answer":"Un plan de seguridad, el horario y un justificante del seguro.","answerIndex":0},{"question":"\xbfQu\xe9 tendr\xeda que demostrar la asociaci\xf3n para obtener una exenci\xf3n de la tasa?","options":["Que el evento se har\xe1 en secreto para evitar aglomeraciones.","Que el evento tiene inter\xe9s p\xfablico y prev\xe9 medidas de limpieza y convivencia.","Que la feria se celebrar\xe1 de madrugada y sin puestos educativos.","Que el barrio renuncia a cualquier servicio municipal durante ese d\xeda."],"answer":"Que el evento tiene inter\xe9s p\xfablico y prev\xe9 medidas de limpieza y convivencia.","answerIndex":1},{"question":"\xbfQu\xe9 ocurre si la solicitud digital se presenta incompleta?","options":["Se cancela autom\xe1ticamente sin posibilidad de correcci\xf3n.","Se archiva durante un a\xf1o sin notificar a la asociaci\xf3n.","Se pide que la documentaci\xf3n faltante se subsane dentro del plazo indicado.","Se transfiere al juzgado para que decida sobre el permiso."],"answer":"Se pide que la documentaci\xf3n faltante se subsane dentro del plazo indicado.","answerIndex":2}]},{"id":2,"topic":"Presentar una queja por una parada inaccesible","dialog":[{"speaker":"Elena","spanish":"Vengo a presentar una queja formal porque la rampa de la parada central lleva meses rota y varias personas en silla de ruedas no pueden subir con seguridad.","english":"I am here to file a formal complaint because the ramp at the central bus stop has been broken for months, and several wheelchair users cannot board safely."},{"speaker":"Se\xf1ora G\xf3mez","spanish":"Para dejar constancia en el expediente, convendr\xeda adjuntar fotograf\xedas, fechas aproximadas de los incidentes y, si fuera posible, los n\xfameros de las l\xedneas afectadas.","english":"To leave a record in the case file, it would be advisable to attach photographs, approximate dates of the incidents, and, if possible, the numbers of the affected routes."},{"speaker":"Elena","spanish":"Los vecinos ya lo comunicaron verbalmente en dos ocasiones, pero nunca recibimos respuesta por escrito ni supimos si alguien hab\xeda revisado la parada.","english":"The neighbors already reported it verbally twice, but we never received a written response or learned whether anyone had inspected the stop."},{"speaker":"Se\xf1ora G\xf3mez","spanish":"Precisamente por eso es importante la presentaci\xf3n formal: as\xed se abre un expediente, se fija un plazo de resoluci\xf3n y la administraci\xf3n debe contestar.","english":"That is precisely why a formal filing matters: it opens a case file, sets a decision deadline, and requires the administration to respond."},{"speaker":"Elena","spanish":"\xbfPodremos consultar el estado del tr\xe1mite o aportar nueva informaci\xf3n si se produce otro accidente?","english":"Will we be able to check the status of the procedure or provide new information if another accident happens?"},{"speaker":"Se\xf1ora G\xf3mez","spanish":"S\xed. Adem\xe1s, si no hubiera respuesta dentro del plazo, podr\xedan presentar un recordatorio o solicitar informaci\xf3n p\xfablica sobre las actuaciones realizadas.","english":"Yes. In addition, if there were no response within the deadline, you could submit a follow-up request or ask for public information about the actions taken."}],"questions":[{"question":"\xbfPor qu\xe9 considera la funcionaria que la presentaci\xf3n formal es importante?","options":["Porque sustituye autom\xe1ticamente la necesidad de reparar la parada.","Porque obliga a la administraci\xf3n a abrir un expediente y a responder dentro de un plazo.","Porque impide que otros vecinos vuelvan a aportar pruebas.","Porque traslada el problema directamente al jurado popular."],"answer":"Porque obliga a la administraci\xf3n a abrir un expediente y a responder dentro de un plazo.","answerIndex":1},{"question":"\xbfQu\xe9 tipo de pruebas recomienda aportar con la queja?","options":["Fotograf\xedas, fechas de los incidentes y datos de las l\xedneas afectadas.","Solo una opini\xf3n personal sin detalles concretos.","Una lista de comercios cercanos y el horario del mercado.","El reglamento interno del ayuntamiento firmado por los vecinos."],"answer":"Fotograf\xedas, fechas de los incidentes y datos de las l\xedneas afectadas.","answerIndex":0},{"question":"Si el ayuntamiento no respondiera a tiempo, \xbfqu\xe9 opci\xf3n menciona la funcionaria?","options":["Esperar indefinidamente sin realizar ninguna otra acci\xf3n.","Presentar un recordatorio o pedir informaci\xf3n p\xfablica sobre lo actuado.","Retirar la queja y abrir un negocio privado de transporte.","Enviar la parada a mantenimiento sin registro oficial."],"answer":"Presentar un recordatorio o pedir informaci\xf3n p\xfablica sobre lo actuado.","answerIndex":1}]},{"id":3,"topic":"Debate en la junta vecinal sobre una ordenanza","dialog":[{"speaker":"Diego","spanish":"La nueva ordenanza sobre terrazas nocturnas pretende reducir el ruido, pero varios hosteleros dicen que perder\xe1n ingresos si se limita demasiado el horario.","english":"The new ordinance on late-night terraces aims to reduce noise, but several restaurant owners say they will lose income if the schedule is restricted too much."},{"speaker":"Patricia","spanish":"Lo comprendo, aunque el derecho al descanso no deber\xeda quedar en segundo plano cuando hay edificios donde la gente lleva a\xf1os sin dormir bien.","english":"I understand that, although the right to rest should not take a back seat when there are buildings where people have spent years unable to sleep properly."},{"speaker":"Diego","spanish":"Lo que me preocupa es que la norma se apruebe sin escuchar con detalle ni a los residentes ni a quienes dependen del trabajo nocturno.","english":"What worries me is that the rule might be approved without listening carefully either to residents or to those who depend on nighttime work."},{"speaker":"Patricia","spanish":"Por eso la junta ha abierto un periodo de consulta; si la participaci\xf3n es real, quiz\xe1 se puedan ajustar horarios y exigir medidas ac\xfasticas m\xe1s eficaces.","english":"That is why the council has opened a consultation period; if participation is genuine, schedules may be adjusted and more effective acoustic measures required."},{"speaker":"Diego","spanish":"Me parecer\xeda razonable siempre que las decisiones se apoyen en datos del barrio y no en una idea abstracta de convivencia.","english":"That would seem reasonable to me as long as the decisions are based on neighborhood data and not on an abstract notion of coexistence."},{"speaker":"Patricia","spanish":"En eso coincidimos: una regulaci\xf3n funciona mejor cuando se percibe como leg\xedtima y no como una imposici\xf3n ciega.","english":"On that we agree: regulation works better when it is seen as legitimate and not as a blind imposition."}],"questions":[{"question":"\xbfQu\xe9 equilibrio intenta buscar la conversaci\xf3n sobre la ordenanza?","options":["Entre el descanso vecinal y la actividad econ\xf3mica nocturna.","Entre el horario escolar y los festivales deportivos.","Entre la construcci\xf3n de una carretera y la apertura de un museo.","Entre la elecci\xf3n del jurado y el registro civil."],"answer":"Entre el descanso vecinal y la actividad econ\xf3mica nocturna.","answerIndex":0},{"question":"\xbfQu\xe9 condici\xf3n pone Patricia para que la consulta tenga sentido?","options":["Que solo participen representantes del sector hostelero.","Que la participaci\xf3n sea real y permita ajustar medidas concretas.","Que la votaci\xf3n se retrase hasta el pr\xf3ximo a\xf1o sin debatir nada.","Que la norma se apruebe antes de escuchar a los residentes."],"answer":"Que la participaci\xf3n sea real y permita ajustar medidas concretas.","answerIndex":1},{"question":"\xbfC\xf3mo resume Patricia una regulaci\xf3n eficaz al final?","options":["Como una orden que debe imponerse aunque nadie la entienda.","Como una norma que se acepta mejor si se percibe como leg\xedtima.","Como un tr\xe1mite que no necesita datos locales ni consultas.","Como una medida provisional que nunca llega a aplicarse."],"answer":"Como una norma que se acepta mejor si se percibe como leg\xedtima.","answerIndex":1}]},{"id":4,"topic":"Citaci\xf3n para jurado y solicitud de aplazamiento","dialog":[{"speaker":"Clara","spanish":"He recibido una citaci\xf3n para formar parte de un jurado justo la semana en que tendr\xe9 que cuidar a mi madre despu\xe9s de una operaci\xf3n, y no s\xe9 c\xf3mo pedir un aplazamiento.","english":"I have received a summons to serve on a jury the very week I will need to care for my mother after surgery, and I do not know how to request a postponement."},{"speaker":"Marcos","spanish":"Un amigo abogado me dijo que no conviene ignorar la citaci\xf3n; hay que presentar una solicitud formal con documentos que acrediten la situaci\xf3n.","english":"A lawyer friend told me it is unwise to ignore the summons; you need to submit a formal request with documents proving the situation."},{"speaker":"Clara","spanish":"Entonces reunir\xe9 los certificados m\xe9dicos y explicar\xe9 por escrito por qu\xe9 mi ausencia pondr\xeda en riesgo un cuidado que no puede delegarse f\xe1cilmente.","english":"Then I will gather the medical certificates and explain in writing why my absence would put at risk care that cannot easily be delegated."},{"speaker":"Marcos","spanish":"Eso es lo adecuado, porque si la petici\xf3n se rechazara, todav\xeda tendr\xedas la obligaci\xf3n de comparecer en la fecha indicada.","english":"That is the right approach, because if the request were rejected, you would still have the obligation to appear on the indicated date."},{"speaker":"Clara","spanish":"Me tranquiliza saber que existe un procedimiento, ya que participar en la justicia es importante, pero tambi\xe9n deber\xeda reconocerse cuando hay una carga familiar excepcional.","english":"It reassures me to know that a procedure exists, since taking part in justice is important, but there should also be recognition when there is an exceptional family burden."},{"speaker":"Marcos","spanish":"Exactamente; los deberes c\xedvicos se sostienen mejor cuando las normas son claras y accesibles para quien necesita justificarse.","english":"Exactly; civic duties hold up better when the rules are clear and accessible for someone who needs to justify their situation."}],"questions":[{"question":"\xbfQu\xe9 consejo principal recibe Clara sobre la citaci\xf3n?","options":["Que la ignore hasta que el juzgado vuelva a escribirle.","Que presente una solicitud formal acompa\xf1ada de pruebas documentales.","Que pida a un vecino que acuda en su lugar sin avisar.","Que espere a que termine la operaci\xf3n para decidir."],"answer":"Que presente una solicitud formal acompa\xf1ada de pruebas documentales.","answerIndex":1},{"question":"\xbfQu\xe9 entiende Clara sobre la participaci\xf3n en un jurado?","options":["Que es opcional y puede cancelarse por tel\xe9fono sin explicaci\xf3n.","Que carece de importancia cuando alguien tiene trabajo pendiente.","Que es valiosa, aunque deber\xedan existir v\xedas para justificar situaciones excepcionales.","Que solo afecta a profesionales del derecho y no a ciudadanos comunes."],"answer":"Que es valiosa, aunque deber\xedan existir v\xedas para justificar situaciones excepcionales.","answerIndex":2},{"question":"Si su solicitud fuera rechazada, \xbfqu\xe9 implicaci\xf3n menciona Marcos?","options":["Que quedar\xeda exenta autom\xe1ticamente durante varios a\xf1os.","Que a\xfan tendr\xeda que comparecer en la fecha prevista.","Que deber\xeda acudir \xfanicamente si el juicio dura m\xe1s de un d\xeda.","Que se archivar\xeda la citaci\xf3n sin m\xe1s tr\xe1mites."],"answer":"Que a\xfan tendr\xeda que comparecer en la fecha prevista.","answerIndex":1}]}],"stories":[{"id":1,"title":"La queja que s\xed obtuvo respuesta","sentences":[{"spanish":"Durante meses, los vecinos de una calle estrecha hab\xedan pedido que se revisara el alumbrado porque varias farolas dejaron de funcionar y aument\xf3 la sensaci\xf3n de inseguridad.","english":"For months, residents on a narrow street had been asking for the lighting to be reviewed because several streetlights stopped working and the sense of insecurity grew."},{"spanish":"Como las llamadas informales no daban resultado, una residente present\xf3 una queja por escrito y adjunt\xf3 fotograf\xedas, fechas y firmas de apoyo.","english":"Since informal calls were getting nowhere, one resident filed a written complaint and attached photographs, dates, and supporting signatures."},{"spanish":"A partir de ese momento, se abri\xf3 un expediente y se comunic\xf3 un plazo dentro del cual deb\xeda emitirse una respuesta motivada.","english":"From that moment on, a case file was opened and a deadline was communicated within which a reasoned response had to be issued."},{"spanish":"Aunque la reparaci\xf3n no fue inmediata, el servicio municipal explic\xf3 qu\xe9 piezas faltaban y cu\xe1ndo se hab\xeda programado la intervenci\xf3n.","english":"Although the repair was not immediate, the municipal service explained which parts were missing and when the intervention had been scheduled."},{"spanish":"Los vecinos valoraron sobre todo que se les tratara como interlocutores leg\xedtimos y no como personas a las que se pudiera ignorar indefinidamente.","english":"The neighbors valued above all that they were treated as legitimate interlocutors and not as people who could be ignored indefinitely."},{"spanish":"La experiencia les record\xf3 que presentar una queja bien documentada no garantiza milagros, pero s\xed obliga a la administraci\xf3n a dar la cara.","english":"The experience reminded them that filing a well-documented complaint does not guarantee miracles, but it does force the administration to be accountable."}]},{"id":2,"title":"Un permiso para la plaza del barrio","sentences":[{"spanish":"Una asociaci\xf3n quiso organizar una feria cultural en la plaza principal para recaudar fondos destinados a un comedor social.","english":"An association wanted to organize a cultural fair in the main square to raise funds for a community kitchen."},{"spanish":"Antes de presentar la solicitud, sus miembros revisaron la ordenanza municipal para asegurarse de que el horario y el sonido cumplieran el reglamento.","english":"Before submitting the request, its members reviewed the municipal ordinance to make sure the schedule and sound levels complied with the regulations."},{"spanish":"Cuando entregaron el expediente, se les indic\xf3 que faltaba un plano de evacuaci\xf3n y que deb\xeda subsanarse esa falta antes de diez d\xedas h\xe1biles.","english":"When they submitted the file, they were told that an evacuation plan was missing and that the omission had to be remedied within ten business days."},{"spanish":"Lejos de interpretarlo como una negativa, entendieron que el tr\xe1mite solo avanzar\xeda si quedaba acreditado que la actividad ser\xeda segura para todos.","english":"Far from taking it as a denial, they understood that the procedure would move forward only if it was shown that the event would be safe for everyone."},{"spanish":"Finalmente, el permiso fue concedido con condiciones espec\xedficas de limpieza, accesibilidad y cierre escalonado.","english":"In the end, the permit was granted with specific conditions regarding cleaning, accessibility, and a phased closing schedule."},{"spanish":"Gracias a ese proceso, la feria no solo se celebr\xf3 con \xe9xito, sino que tambi\xe9n se convirti\xf3 en un ejemplo de participaci\xf3n ciudadana bien preparada.","english":"Thanks to that process, the fair was not only held successfully, but also became an example of well-prepared civic participation."}]},{"id":3,"title":"El deber de participar","sentences":[{"spanish":"Clara pens\xf3 al principio que la citaci\xf3n para jurado era una molestia absurda que solo interrumpir\xeda una semana ya complicada.","english":"At first Clara thought the jury summons was an absurd nuisance that would only interrupt an already difficult week."},{"spanish":"Sin embargo, cuando ley\xf3 con atenci\xf3n la documentaci\xf3n, comprendi\xf3 que se trataba de una responsabilidad civil vinculada al derecho de todos a un proceso justo.","english":"However, when she read the paperwork carefully, she understood that it was a civic responsibility tied to everyone\'s right to a fair process."},{"spanish":"Como deb\xeda cuidar a su madre tras una operaci\xf3n, present\xf3 una solicitud razonada para que se valorara un aplazamiento excepcional.","english":"Because she had to care for her mother after surgery, she submitted a reasoned request so that an exceptional postponement could be considered."},{"spanish":"La respuesta no lleg\xf3 de inmediato, pero al menos qued\xf3 claro qu\xe9 pruebas se requer\xedan y qu\xe9 plazos se hab\xedan fijado para decidir.","english":"The response did not arrive immediately, but at least it became clear what evidence was required and what deadlines had been set to decide."},{"spanish":"Esa transparencia hizo que Clara dejara de ver el procedimiento como una carga opaca y empezara a entenderlo como una obligaci\xf3n que tambi\xe9n deb\xeda respetar sus circunstancias.","english":"That transparency led Clara to stop seeing the procedure as an opaque burden and begin to understand it as an obligation that should also respect her circumstances."},{"spanish":"Al final, m\xe1s que resolver solo su caso, la experiencia le ense\xf1\xf3 que las instituciones ganan legitimidad cuando explican bien c\xf3mo deben cumplirse los deberes p\xfablicos.","english":"In the end, more than merely resolving her case, the experience taught her that institutions gain legitimacy when they clearly explain how public duties must be fulfilled."}]}],"speaking":{"title":"Hablar sobre vida c\xedvica y tr\xe1mites p\xfablicos","description":"Practica solicitudes formales, quejas documentadas y explicaciones sobre derechos, deberes y participaci\xf3n ciudadana.","questions_and_answers":[{"question":{"spanish":"\xbfC\xf3mo solicitar\xedas un permiso para usar un espacio p\xfablico?","english":"How would you request a permit to use a public space?"},"answer":{"spanish":"Presentar\xeda una solicitud por escrito con la fecha, el horario, las medidas de seguridad y la documentaci\xf3n exigida.","english":"I would submit a written request with the date, schedule, safety measures, and required documentation."}},{"question":{"spanish":"\xbfPara qu\xe9 sirve presentar una queja formal y no solo verbal?","english":"What is the purpose of filing a formal complaint rather than just making a verbal one?"},"answer":{"spanish":"Sirve para que se abra un expediente y la administraci\xf3n tenga la obligaci\xf3n de responder dentro de un plazo.","english":"It serves to open a case file and require the administration to respond within a deadline."}},{"question":{"spanish":"\xbfQu\xe9 documentos podr\xedan pedirte para un tr\xe1mite municipal?","english":"What documents might they ask you for in a municipal procedure?"},"answer":{"spanish":"Podr\xedan pedirme un formulario firmado, un documento de identidad y pruebas que justifiquen la solicitud.","english":"They might ask me for a signed form, an ID document, and evidence supporting the request."}},{"question":{"spanish":"Formula una petici\xf3n cort\xe9s a un funcionario p\xfablico.","english":"Make a polite request to a public official."},"answer":{"spanish":"Le agradecer\xeda que me indicara qu\xe9 pasos debo seguir para subsanar la documentaci\xf3n pendiente.","english":"I would appreciate it if you could tell me what steps I must follow to correct the pending documentation."}},{"question":{"spanish":"\xbfQu\xe9 har\xedas si una oficina no respondiera dentro del plazo legal?","english":"What would you do if an office did not respond within the legal deadline?"},"answer":{"spanish":"Presentar\xeda un recordatorio formal y pedir\xeda informaci\xf3n sobre el estado exacto del expediente.","english":"I would submit a formal reminder and request information about the exact status of the case file."}},{"question":{"spanish":"Explica por qu\xe9 la participaci\xf3n ciudadana mejora una ordenanza.","english":"Explain why citizen participation improves an ordinance."},"answer":{"spanish":"La mejora porque permite que se escuchen necesidades reales antes de que la norma se apruebe definitivamente.","english":"It improves it because it allows real needs to be heard before the rule is approved definitively."}},{"question":{"spanish":"\xbfQu\xe9 significa tener derecho de audiencia en un procedimiento?","english":"What does it mean to have the right to be heard in a procedure?"},"answer":{"spanish":"Significa poder presentar alegaciones y pruebas antes de que la administraci\xf3n tome una decisi\xf3n que me afecte.","english":"It means being able to present arguments and evidence before the administration makes a decision that affects me."}},{"question":{"spanish":"Usa un registro formal para pedir una cita previa.","english":"Use a formal register to request an appointment."},"answer":{"spanish":"Quisiera solicitar una cita previa para revisar un tr\xe1mite que sigue pendiente de resoluci\xf3n.","english":"I would like to request an appointment to review a procedure that is still awaiting resolution."}},{"question":{"spanish":"\xbfQu\xe9 debe incluir una denuncia bien documentada?","english":"What should a well-documented complaint include?"},"answer":{"spanish":"Debe incluir fechas, hechos verificables, pruebas documentales y una petici\xf3n clara de actuaci\xf3n.","english":"It should include dates, verifiable facts, documentary evidence, and a clear request for action."}},{"question":{"spanish":"\xbfPor qu\xe9 conviene leer el reglamento antes de organizar un evento?","english":"Why is it wise to read the regulations before organizing an event?"},"answer":{"spanish":"Conviene leerlo para evitar incumplimientos y para saber qu\xe9 condiciones deben respetarse desde el principio.","english":"It is wise to read it to avoid violations and to know what conditions must be respected from the start."}},{"question":{"spanish":"Si te citaran para un jurado, \xbfqu\xe9 har\xedas si tuvieras una causa grave para aplazarlo?","english":"If you were summoned for jury duty, what would you do if you had a serious reason to postpone it?"},"answer":{"spanish":"Presentar\xeda una solicitud formal con certificados y explicar\xeda por qu\xe9 no puedo comparecer en esa fecha.","english":"I would submit a formal request with certificates and explain why I cannot appear on that date."}},{"question":{"spanish":"\xbfQu\xe9 diferencia hay entre una respuesta verbal y una resoluci\xf3n motivada?","english":"What is the difference between a verbal response and a reasoned decision?"},"answer":{"spanish":"La resoluci\xf3n motivada deja constancia oficial de las razones y permite recurrir si fuera necesario.","english":"A reasoned decision leaves an official record of the reasons and allows an appeal if necessary."}},{"question":{"spanish":"Menciona un servicio p\xfablico que deba tratarse como esencial.","english":"Mention a public service that should be treated as essential."},"answer":{"spanish":"El transporte accesible deber\xeda tratarse como esencial porque condiciona el acceso al trabajo, la salud y la educaci\xf3n.","english":"Accessible transportation should be treated as essential because it affects access to work, healthcare, and education."}},{"question":{"spanish":"\xbfC\xf3mo pedir\xedas informaci\xf3n sobre un expediente atrasado?","english":"How would you request information about a delayed case file?"},"answer":{"spanish":"Solicitar\xeda por escrito que se me informe del estado del expediente y de las actuaciones ya realizadas.","english":"I would request in writing that I be informed of the status of the case file and of the actions already taken."}},{"question":{"spanish":"Usa el subjuntivo para expresar una exigencia administrativa.","english":"Use the subjunctive to express an administrative requirement."},"answer":{"spanish":"Es necesario que la solicitud est\xe9 firmada electr\xf3nicamente para que pueda admitirse a tr\xe1mite.","english":"It is necessary for the request to be electronically signed so that it can be accepted for processing."}},{"question":{"spanish":"\xbfPor qu\xe9 puede ser \xfatil la mediaci\xf3n en un conflicto vecinal?","english":"Why can mediation be useful in a neighborhood conflict?"},"answer":{"spanish":"Puede ser \xfatil porque permite que las partes busquen un acuerdo antes de que el problema se vuelva m\xe1s hostil.","english":"It can be useful because it allows the parties to seek an agreement before the problem becomes more hostile."}},{"question":{"spanish":"\xbfQu\xe9 derecho protege el acceso a la informaci\xf3n p\xfablica?","english":"What right does access to public information protect?"},"answer":{"spanish":"Protege el derecho de la ciudadan\xeda a saber c\xf3mo act\xfaan las instituciones y en qu\xe9 basan sus decisiones.","english":"It protects the public\'s right to know how institutions act and what they base their decisions on."}},{"question":{"spanish":"Describe una situaci\xf3n en la que tendr\xedas que subsanar documentaci\xf3n.","english":"Describe a situation in which you would have to remedy missing documents."},"answer":{"spanish":"Tendr\xeda que subsanar la documentaci\xf3n si presentara una solicitud de permiso sin adjuntar el seguro o un plano exigido por la ordenanza.","english":"I would have to correct the documentation if I submitted a permit request without attaching the insurance or a plan required by the ordinance."}},{"question":{"spanish":"\xbfQu\xe9 se gana cuando un tr\xe1mite es claro y accesible?","english":"What is gained when a procedure is clear and accessible?"},"answer":{"spanish":"Se gana confianza institucional y es m\xe1s probable que la gente cumpla las normas sin sentirse desorientada.","english":"Institutional trust is gained and people are more likely to follow the rules without feeling lost."}},{"question":{"spanish":"Resume la relaci\xf3n entre derechos y deberes en la vida c\xedvica.","english":"Summarize the relationship between rights and duties in civic life."},"answer":{"spanish":"Los derechos se vuelven m\xe1s s\xf3lidos cuando las instituciones respetan los procedimientos y la ciudadan\xeda participa de manera informada.","english":"Rights become stronger when institutions respect procedures and citizens participate in an informed way."}}]}}}')}}]);